#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding mast-cell-activation-syndrome-assessment (15 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    occupation:string! \
    ethnicity:string! \
    contact_phone:string! \
    contact_email:string! \
    emergency_contact_name:string! \
    emergency_contact_phone:string! \
    gp_name:string! \
    gp_practice:string! \
    --htmx

cargo loco generate scaffold assessment_symptom_overview \
    assessment:references \
    symptom_onset_date:date \
    symptom_duration:string! \
    symptom_pattern:string! \
    symptom_frequency:string! \
    worst_symptom_description:text! \
    overall_severity:int \
    previous_mcas_diagnosis:string! \
    previous_mastocytosis_diagnosis:string! \
    family_history_mast_cell:string! \
    family_history_details:text! \
    --htmx

cargo loco generate scaffold assessment_dermatological_symptoms \
    assessment:references \
    flushing:string! \
    flushing_severity:int \
    flushing_frequency:string! \
    urticaria:string! \
    urticaria_severity:int \
    angioedema:string! \
    angioedema_location:text! \
    pruritus:string! \
    pruritus_severity:int \
    dermatographism:string! \
    skin_lesions:text! \
    dermatological_notes:text! \
    --htmx

cargo loco generate scaffold assessment_gastrointestinal_symptoms \
    assessment:references \
    abdominal_pain:string! \
    abdominal_pain_severity:int \
    nausea:string! \
    vomiting:string! \
    diarrhoea:string! \
    diarrhoea_frequency:string! \
    bloating:string! \
    gastro_oesophageal_reflux:string! \
    dysphagia:string! \
    food_intolerances:text! \
    weight_change:string! \
    weight_change_amount_kg:double \
    gastrointestinal_notes:text! \
    --htmx

cargo loco generate scaffold assessment_cardiovascular_symptoms \
    assessment:references \
    tachycardia:string! \
    resting_heart_rate:int \
    hypotension:string! \
    systolic_bp:int \
    diastolic_bp:int \
    presyncope:string! \
    syncope:string! \
    syncope_frequency:string! \
    palpitations:string! \
    chest_pain:string! \
    orthostatic_intolerance:string! \
    anaphylaxis_history:string! \
    anaphylaxis_episode_count:int \
    carries_adrenaline_auto_injector:string! \
    cardiovascular_notes:text! \
    --htmx

cargo loco generate scaffold assessment_respiratory_symptoms \
    assessment:references \
    wheezing:string! \
    dyspnoea:string! \
    dyspnoea_severity:int \
    nasal_congestion:string! \
    rhinorrhoea:string! \
    throat_tightness:string! \
    stridor:string! \
    cough:string! \
    cough_type:string! \
    asthma_diagnosis:string! \
    peak_flow_lpm:int \
    respiratory_notes:text! \
    --htmx

cargo loco generate scaffold assessment_neurological_symptoms \
    assessment:references \
    headaches:string! \
    headache_severity:int \
    headache_frequency:string! \
    brain_fog:string! \
    brain_fog_severity:int \
    dizziness:string! \
    paraesthesia:string! \
    paraesthesia_location:text! \
    insomnia:string! \
    fatigue:string! \
    fatigue_severity:int \
    anxiety:string! \
    depression:string! \
    neurological_notes:text! \
    --htmx

cargo loco generate scaffold assessment_triggers_and_patterns \
    assessment:references \
    heat_trigger:string! \
    cold_trigger:string! \
    stress_trigger:string! \
    exercise_trigger:string! \
    food_trigger:string! \
    food_trigger_details:text! \
    alcohol_trigger:string! \
    medication_trigger:string! \
    medication_trigger_details:text! \
    fragrance_chemical_trigger:string! \
    insect_sting_trigger:string! \
    hormonal_trigger:string! \
    hormonal_trigger_details:text! \
    infection_trigger:string! \
    other_triggers:text! \
    diurnal_pattern:string! \
    seasonal_pattern:string! \
    seasonal_pattern_details:text! \
    --htmx

cargo loco generate scaffold assessment_laboratory_results \
    assessment:references \
    serum_tryptase:double \
    serum_tryptase_date:date \
    serum_tryptase_elevated:string! \
    plasma_histamine:double \
    plasma_histamine_date:date \
    urine_n_methylhistamine:double \
    urine_n_methylhistamine_date:date \
    urine_prostaglandin_d2:double \
    urine_prostaglandin_d2_date:date \
    urine_leukotriene_e4:double \
    urine_leukotriene_e4_date:date \
    chromogranin_a:double \
    chromogranin_a_date:date \
    serum_ige_total:double \
    full_blood_count_notes:text! \
    bone_marrow_biopsy:string! \
    bone_marrow_biopsy_result:text! \
    additional_lab_notes:text! \
    --htmx

cargo loco generate scaffold assessment_current_treatment \
    assessment:references \
    h1_antihistamine:string! \
    h1_antihistamine_name:string! \
    h1_antihistamine_dose:string! \
    h2_antihistamine:string! \
    h2_antihistamine_name:string! \
    h2_antihistamine_dose:string! \
    mast_cell_stabiliser:string! \
    mast_cell_stabiliser_name:string! \
    leukotriene_inhibitor:string! \
    leukotriene_inhibitor_name:string! \
    corticosteroids:string! \
    corticosteroid_details:text! \
    adrenaline_auto_injector_prescribed:string! \
    omalizumab:string! \
    other_medications:text! \
    low_histamine_diet:string! \
    avoidance_strategies:text! \
    treatment_effectiveness:string! \
    treatment_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    total_symptom_score:int! \
    dermatological_score:int! \
    gastrointestinal_score:int! \
    cardiovascular_score:int! \
    respiratory_score:int! \
    neurological_score:int! \
    organ_system_count:int! \
    severity_level:string! \
    trigger_count:int! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
